import TypeBadge from '$lib/components/TypeBadge.svelte';

export let data: PageData;

$: session = data.session;
$: initialEntries = data.feedEntries ?? [];

// Create SSE stream for live updates (non-terminal sessions)
let stream = session && session.type !== 'terminal' ? createSessionStream(session.id) : null;
$: allEntries = stream ? [...initialEntries, ...stream.entries] : initialEntries;
$: isRunning = session?.status === 'running';

async function handleSubmit(event: CustomEvent<string>): Promise<void> {
	if (!session) return;
	await fetch(`/api/sessions/${session.id}/input`, {
		method: 'POST',
		headers: { 'Content-Type': 'application/json' },
		body: JSON.stringify({ content: event.detail })
	});
}

const quickCommands = ['git status', 'git log --oneline -5', 'ls -la', 'pwd'];

onDestroy(() => {
	stream?.destroy();
});

